from llama_stack_client import AgentSession

def monitor_collective_turns(sessions):
    total_turns = 0
    stalled_agents = []
    for session in sessions:
        stats = session.get_stats()
        total_turns += stats['turns_used']
        if stats['turns_used'] >= stats['max_turns'] * 0.9:
            stalled_agents.append({
                'agent_id': session.agent_id,
                'turns_used': stats['turns_used'],
                'max_turns': stats['max_turns'],
                'progress': stats.get('task_progress', 0)
            })
    return {
        'total_turns': total_turns,
        'avg_turns_per_agent': total_turns / len(sessions),
        'stalled_agents': stalled_agents,
        'warning': total_turns > len(sessions) * 10
    }

