from collections import deque
from llama_stack_client import ToolCall

class OrderedToolQueue:
    def __init__(self):
        self.queue = deque()
        self.response_map = {}

    def submit_tool_call(self, call_id, tool_call: ToolCall):
        self.queue.append(call_id)
        # Store tool call metadata
        self.response_map[call_id] = tool_call.dict()

    def process_response(self, response):
        call_id = response.call_id
        if call_id in self.response_map:
            # Validate against stored schema
            expected = self.response_map[call_id]
            if self._validate_schema(response, expected):
                return {'ordered': True, 'response': response.dict()}
            else:
                return {'ordered': False, 'error': 'Schema mismatch'}
        return {'ordered': False, 'error': 'Unknown call_id'}

